import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void typicalDepositWithdrawDeposit() {
        // 0 + 500 - 200 + 100 = 400
        assertEquals(400L,
                new Solution().finalBalance(new String[]{"DEPOSIT:500", "WITHDRAW:200", "DEPOSIT:100"}));
    }

    @Test
    void emptyEvents() {
        // Identity element: no events means balance stays at 0
        assertEquals(0L,
                new Solution().finalBalance(new String[]{}));
    }

    @Test
    void singleDeposit() {
        assertEquals(750L,
                new Solution().finalBalance(new String[]{"DEPOSIT:750"}));
    }

    @Test
    void withdrawBelowZero() {
        // Ledger allows negative balance — no overdraft guard
        assertEquals(-300L,
                new Solution().finalBalance(new String[]{"WITHDRAW:300"}));
    }

    @Test
    void orderMatters() {
        // Same amounts in different order produce the same numeric total here,
        // but this sequence verifies the intermediate-negative path is traversed
        // and the algorithm accumulates correctly left-to-right.
        // 0 - 200 + 500 = 300  vs  0 + 500 - 200 = 300 — same end balance,
        // so we use a case where order produces a distinct final value:
        // WITHDRAW:1000, DEPOSIT:500 → -500  vs  DEPOSIT:500, WITHDRAW:1000 → -500 (same here)
        // Use asymmetric amounts so any reversal would mismatch:
        // DEPOSIT:100, DEPOSIT:200, WITHDRAW:50 → 250
        // reversed: WITHDRAW:50, DEPOSIT:200, DEPOSIT:100 → also 250 (commutative)
        // True order sensitivity appears in the WITHDRAW-below-zero + further ops:
        // WITHDRAW:600, DEPOSIT:100 → -500  vs  DEPOSIT:100, WITHDRAW:600 → -500 (same)
        // For a long chain the sum is commutative — but the real test is that the
        // student applies ALL events and doesn't short-circuit on negative balance.
        assertEquals(250L,
                new Solution().finalBalance(new String[]{
                        "DEPOSIT:100", "DEPOSIT:200", "WITHDRAW:50"}));
    }

    @Test
    void netZeroBalance() {
        // All deposits cancelled by matching withdrawals
        assertEquals(0L,
                new Solution().finalBalance(new String[]{"DEPOSIT:100", "WITHDRAW:100"}));
    }

    @Test
    void largeAmounts() {
        // Verify long arithmetic is used (not int overflow)
        assertEquals(3_000_000_000L,
                new Solution().finalBalance(new String[]{
                        "DEPOSIT:2000000000", "DEPOSIT:1000000000"}));
    }
}
